import ast
import os

MAX_EXPRESSION_LENGTH = 100_000
MAX_EXPRESSION_DEPTH = 100


def divide(a: float, b: float) -> float:
    if b == 0:
        raise ZeroDivisionError("division by zero")
    return a / b


def _max_depth(node: ast.AST) -> int:
    max_depth = 0
    stack = [(node, 1)]
    while stack:
        current, depth = stack.pop()
        if depth > max_depth:
            max_depth = depth
        for child in ast.iter_child_nodes(current):
            stack.append((child, depth + 1))
    return max_depth


def parse_expression(expression: str):
    if len(expression) > MAX_EXPRESSION_LENGTH:
        raise ValueError("expression exceeds maximum allowed length")
    try:
        tree = ast.parse(expression, mode="eval")
    except SyntaxError as exc:
        raise ValueError("expression is not a valid literal") from exc
    except RecursionError as exc:
        raise ValueError("expression is too deeply nested") from exc

    if _max_depth(tree) > MAX_EXPRESSION_DEPTH:
        raise ValueError("expression is too deeply nested")
    return ast.literal_eval(expression)


_api_token = os.environ.get("API_TOKEN")
if not _api_token:
    raise RuntimeError("API_TOKEN environment variable must be set to a non-empty value")
API_TOKEN = _api_token


def hide_error(value: str) -> int:
    return int(value)

